// ============================================================================
// ESCUDO DE ERRORES EXTREMO
// ============================================================================
class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { hasError: false, errorMsg: '' }; }
  static getDerivedStateFromError(error) { return { hasError: true }; }
  componentDidCatch(error) { this.setState({ errorMsg: error && error.message ? error.message : String(error) }); }
  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 p-6 print:hidden">
          <AlertTriangle size={60} className="text-red-500 mb-4" />
          <h2 className="text-2xl font-black text-black uppercase mb-2">Sistema Protegido de Caída</h2>
          <p className="text-gray-500 text-sm mb-6">{this.state.errorMsg}</p>
          <button onClick={() => window.location.reload()} className="bg-black text-white font-black px-8 py-4 rounded-xl uppercase tracking-widest text-xs shadow-lg">Recargar Interfaz</button>
        </div>
      );
    }
    return this.props.children; 
  }
}

// ============================================================================
// RELOJ EN VIVO — Componente aislado para evitar re-render del árbol completo
// ============================================================================
const LiveClock = React.memo(() => {
  const [time, setTime] = useState(new Date());
  useEffect(() => {
    const id = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(id);
  }, []);
  return (
    <div className="hidden lg:flex items-center gap-2 border border-gray-800 rounded-xl px-4 py-2 bg-gray-900 select-none mx-2">
      <span className="text-orange-500 opacity-60" style={{fontSize:'10px'}}>⏱</span>
      <div>
        <p className="text-[11px] font-black text-orange-400 tabular-nums leading-none tracking-wider">
          {time.toLocaleTimeString('es-VE',{hour:'2-digit',minute:'2-digit',second:'2-digit'})}
        </p>
        <p className="text-[8px] text-gray-500 capitalize leading-none mt-0.5">
          {time.toLocaleDateString('es-VE',{weekday:'short',day:'2-digit',month:'short',year:'numeric'})}
        </p>
      </div>
    </div>
  );
});

