  // ── MIGRAR FACTURAS DE MAYO 2026 → NOTAS DE ENTREGA (PROCESADA) ─────────────
  useEffect(() => {
    if(!invoices || !appUser || invoices.length===0) return;
    if(localStorage.getItem('migrated_invoices_to_ne_mayo2026')==='done') return;
    const mayoInvoices = invoices.filter(inv => (inv.fecha||'').startsWith('2026-05'));
    if(mayoInvoices.length===0) { localStorage.setItem('migrated_invoices_to_ne_mayo2026','done'); return; }
    const existingNeIds = new Set((notasEntrega||[]).map(n=>n.facturaId).filter(Boolean));
    const toMigrate = mayoInvoices.filter(inv => !existingNeIds.has(inv.id) && !existingNeIds.has(inv.documento));
    if(toMigrate.length===0) { localStorage.setItem('migrated_invoices_to_ne_mayo2026','done'); return; }
    const run = async () => {
      try {
        const existingNums = (notasEntrega||[]).map(n=>parseInt((n.id||'NE-00000').replace('NE-',''))||0);
        let counter = Math.max(0,...existingNums);
        const sorted = [...toMigrate].sort((a,b)=>(a.fecha||'').localeCompare(b.fecha||''));
        for(const inv of sorted) {
          counter++;
          const neId = 'NE-'+String(counter).padStart(5,'0');
          const items = (inv.itemsFacturados||[]).map(it=>({
            invCode: it.invCode||it.fgId||'', desc: it.desc||'', cantidad: it.cantidad||0,
            precioUnit: it.precioUnit||0, unit: it.unidad||'und', costoUnit: it.costoUnit||0
          }));
          const base = parseNum(inv.montoBase||0);
          const ivaAmt = parseFloat((parseNum(inv.iva||0)).toFixed(2));
          await setDoc(getDocRef('notasEntrega', neId), {
            id: neId, fecha: inv.fecha||getTodayDate(),
            clientRif: inv.clientRif||'', clientName: inv.clientName||'',
            clientAddress: inv.clientAddress||'', vendedor: inv.vendedor||'',
            items, montoBase: base, ivaAmt, total: parseNum(inv.total||0),
            costoTotal: items.reduce((s,it)=>s+it.cantidad*it.costoUnit,0),
            aplicaIva: inv.aplicaIva||'SI', status: 'PROCESADA',
            facturaId: inv.id||inv.documento||'', opRelacionada: inv.opAsignada||'',
            ncConsignacion: inv.ncAsignada||'', observaciones: '',
            timestamp: inv.timestamp||Date.now(), updatedAt: Date.now(), user: 'MIGRACIÓN MAYO 2026'
          });
        }
        localStorage.setItem('migrated_invoices_to_ne_mayo2026','done');
      } catch(e) { console.error('Migración NE:', e); }
    };
    run();
  }, [invoices?.length, notasEntrega?.length, appUser?.username]);
  // Estados de respaldo declarados aquí para que el useEffect los pueda usar sin TDZ
  const [backupFreq, setBackupFreq] = useState(() => localStorage.getItem('backupFreq') || 'manual');
  const [backupLastRun, setBackupLastRun] = useState(() => localStorage.getItem('backupLastRun') || '');
  const [backupTime, setBackupTime] = useState(() => localStorage.getItem('backupTime') || '08:00');

  useEffect(() => {
    if (backupFreq === 'manual') return;
    const checkAndBackup = () => {
      if (!appUser) return;
      const now = new Date();
      const nowHHMM = `${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
      const today = getTodayDate();
      const lastRun = localStorage.getItem('backupLastRun') || '';
      const lastRunDate = lastRun;
      const diffDays = lastRunDate ? Math.floor((new Date(today) - new Date(lastRunDate)) / 86400000) : 999;
      let shouldRun = false;
      if (backupFreq === 'diario' && diffDays >= 1 && nowHHMM === backupTime) shouldRun = true;
      if (backupFreq === 'semanal' && diffDays >= 7 && nowHHMM === backupTime) shouldRun = true;
      if (backupFreq === 'mensual' && diffDays >= 30 && nowHHMM === backupTime) shouldRun = true;
      if (shouldRun) {
        handleBackupData();
        setDialog({ title: '💾 Respaldo Automático', text: `Respaldo automático ejecutado a las ${backupTime}. Frecuencia: ${backupFreq}.`, type: 'alert' });
      }
    };
    // Verificar cada minuto
    const interval = setInterval(checkAndBackup, 60000);
    return () => clearInterval(interval);
  }, [backupFreq, backupTime, appUser]);

  // ============================================================================
  // ASIENTOS CONTABLES AUTOMÁTICOS
  // Cuentas:
  //   1.1.03.01.004 MATERIA PRIMA (INV-FINAL)           — inventario MP
  //   1.1.03.01.003 INVENTARIO DE CONSUMIBLES           — inventario consumibles
  //   1.1.03.01.007 
  //   1.1.03.01.008 PRODUCTOS TERMINADOS (INV-FINAL)    — terminados
  //   5.1.01.01.001 COSTO DE PRODUCCIÓN Y VENTAS        — costo al facturar
  //   4.1.01.01.000 INGRESOS POR MAQUILA                — ingresos al facturar
  // ============================================================================
  const getCtaInventario = (categoria) => {
    const cat = (categoria || '').toLowerCase();
    if (cat.includes('materia prima')) return '1.1.03.01.004';
    return '1.1.03.01.003'; // consumibles, tintas, quimicos, etc.
  };

  const getNombreCta = (codigo) => {
    const map = {
      '1.1.03.01.004': 'MATERIA PRIMA (INV-FINAL)',
      '1.1.03.01.003': 'INVENTARIO DE CONSUMIBLES',
      '1.1.03.01.007': 'PRODUCTOS EN PROCESO (INV-INICIAL)',
      '1.1.03.01.008': 'PRODUCTOS TERMINADOS (INV-FINAL)',
      '5.1.01.01.001': 'COSTO DE PRODUCCIÓN Y VENTAS',
      '4.1.01.01.000': 'INGRESOS POR PRODUCCIÓN',
    };
    return map[codigo] || codigo;
  };

  const registrarAsientoContable = async (firebatchOrNull, { debito, credito, monto, descripcion, referencia, fecha }) => {
    if (monto <= 0) return;
    const asientoId = `AST-${Date.now()}-${Math.floor(Math.random()*9999)}`;
    const asiento = {
      id: asientoId,
      fecha: fecha || getTodayDate(),
      descripcion: (descripcion || '').toUpperCase(),
      referencia: (referencia || '').toUpperCase(),
      debito: { codigo: debito, nombre: getNombreCta(debito), monto },
      credito: { codigo: credito, nombre: getNombreCta(credito), monto },
      monto,
      user: appUser?.name || 'Sistema',
      timestamp: Date.now(),
    };
    if (firebatchOrNull) {
      firebatchOrNull.set(getDocRef('asientosContables', asientoId), asiento);
    } else {
      await setDoc(getDocRef('asientosContables', asientoId), asiento);
    }
  };

  const clearAllReports = useCallback(() => {
    setShowReqReport(false); setShowClientReport(false); setShowGeneralInvoicesReport(false);
    setShowNewReqPanel(false); setShowNewInvoicePanel(false); setEditingClientId(null); setEditingReqId(null); 
    setShowSingleReqReport(null); setShowSingleInvoice(null); setInvoiceSearchTerm(''); setShowWorkOrder(null); 
    setShowPhaseReport(null); setShowFiniquito(null); setSelectedPhaseReqId(null); setReqToApprove(null); setShowMovementReceipt(null);
    setShowPurchaseOrder(false); setViewingPO(null); setShowFiniquitoOP(null);
  }, []);

  // ============================================================================
  // LOGICA TOMA FÍSICA Y AJUSTE MASIVO DE INVENTARIO
  // ============================================================================
  const handleProcessTomaFisica = async () => {
    const changes = [];

    // Recopilar todos los ajustes pendientes en physicalCounts
    for (const item of inventory) {
      const val = physicalCounts[item.id];
      if (val !== undefined && val !== '') {
        const newStock = parseNum(val);
        const diff = newStock - parseNum(item.stock || 0);
        if (Math.abs(diff) > 0.0001) changes.push({ kind: 'inventory', item, newStock, diff });
      }
    }


    // FG Terminados and PT inventory items (no WIP)
    for (const [pfId, val] of Object.entries(physicalCounts)) {
      if (val === undefined || val === '' || pfId.startsWith('WIP-') || pfId.includes('||')) continue;
      if (pfId.startsWith('FG-TF-')) {
        const grpKey = pfId.replace('FG-TF-','');
        const fgDocs = (finishedGoodsInventory||[]).filter(fg => {
          const key = `${fg.categoria||fg.producto||''}__${fg.cliente||''}__${fg.tipoProducto}`;
          return key === grpKey && (parseNum(fg.kgProducidos)>0 || parseNum(fg.millares)>0);
        });
        if (fgDocs.length > 0) {
          const esTermo = fgDocs[0].tipoProducto === 'TERMOENCOGIBLE';
          const sysStock = fgDocs.reduce((s,fg)=>s+(esTermo?parseNum(fg.kgProducidos):parseNum(fg.millares)),0);
          const newStock = parseNum(val);
          const diff = newStock - sysStock;
          if (Math.abs(diff) > 0.0001) changes.push({ kind: 'fg', fgDocs, esTermo, sysStock, newStock, diff, pfId });
        }
      } else if (!pfId.startsWith('INV-PT-')) {
        // PT inventory by cleanCode OR regular inventory item
        const cleanCode = pfId;
        const ptDocs = (inventory||[]).filter(i => {
          const cc = (i.displayId||(i.id||'').split('___')[0]).replace(/-RESTORE$/i,'').replace(/-BACKUP$/i,'').trim();
          return cc === cleanCode;
        });
        if(ptDocs.length > 0) {
          const wh = {};
          ptDocs.forEach(d=>{ const alm=d.almacen||(d.id||'').split('___')[1]?.replace(/-/g,' ')||''; const qty=parseNum(d.stock||0); if(!wh[alm]||qty>wh[alm]) wh[alm]=qty; });
          const sysStock = Object.values(wh).reduce((s,v)=>s+v,0);
          const newStock = parseNum(val);
          const diff = newStock - sysStock;
          if(Math.abs(diff)>0.0001) changes.push({ kind:'pt_clean', ptDocs, cleanCode, sysStock, newStock, diff });
        } else {
          const invItem = (inventory||[]).find(i=>i.id===pfId);
          if(invItem) { const newStock=parseNum(val); const diff=newStock-parseNum(invItem.stock||0); if(Math.abs(diff)>0.0001) changes.push({kind:'inventory',item:invItem,newStock,diff}); }
        }
      }
    }

    if (changes.length === 0) return setDialog({title:'Aviso', text:'No se encontraron diferencias para ajustar.', type:'alert'});

    setDialog({ title: 'Procesar Toma Física', text: `Se ajustarán ${changes.length} ítem(s): Inventario General y Terminados. ¿Confirmar?`, type: 'confirm',
      onConfirm: async () => {
        try {
          const batch = writeBatch(db); const timestamp = Date.now(); let count = 0;
          for (const ch of changes) {
            count++;
            if (ch.kind === 'inventory') {
              const qty = Math.abs(ch.diff); const movId = `TF-${timestamp}-${ch.item.id}`;
              batch.set(getDocRef('inventoryMovements', movId), { id:movId, date:tomaFisicaDate||getTodayDate(), itemId:ch.item.id, itemName:ch.item.desc, type:ch.diff>0?'AJUSTE (POSITIVO)':'AJUSTE (NEGATIVO)', qty, cost:ch.item.cost, totalValue:qty*ch.item.cost, reference:'TOMA FÍSICA', notes:'AJUSTE MASIVO', timestamp, user:appUser?.name||'Sistema' });
              batch.update(getDocRef('inventory', ch.item.id), { stock: ch.newStock });
            } else if (ch.kind === 'fg') {
              const mainDoc = ch.fgDocs.sort((a,b)=>(b.timestamp||0)-(a.timestamp||0))[0];
              batch.update(getDocRef('finishedGoodsInventory', mainDoc.id), ch.esTermo?{kgProducidos:ch.newStock}:{millares:ch.newStock});
              const movId = `TF-FG-${timestamp}-${mainDoc.id}`;
              batch.set(getDocRef('inventoryMovements', movId), { id:movId, date:tomaFisicaDate||getTodayDate(), itemId:`FG::${mainDoc.id}`, itemName:`${mainDoc.categoria||mainDoc.producto||'FG'} — ${mainDoc.cliente||''}`, type:ch.diff>0?'AJUSTE (POSITIVO)':'AJUSTE (NEGATIVO)', qty:Math.abs(ch.diff), cost:mainDoc.costoUnitario||0, totalValue:Math.abs(ch.diff)*(mainDoc.costoUnitario||0), reference:'TOMA FÍSICA', notes:'AJUSTE MASIVO PT', timestamp, user:appUser?.name||'Sistema', isFG:true });
            } else if (ch.kind === 'pt_clean') {
              const sysTotal = ch.sysStock||1;
              for(const doc of ch.ptDocs) {
                const alm = doc.almacen||(doc.id||'').split('___')[1]?.replace(/-/g,' ')||'';
                const whKey = `${ch.cleanCode}||${alm}`;
                const whCount = physicalCounts[whKey];
                const newDocStock = whCount!==undefined&&whCount!=='' ? parseNum(whCount) : Math.round((parseNum(doc.stock||0)/sysTotal)*ch.newStock*100)/100;
                batch.update(getDocRef('inventory', doc.id), { stock:newDocStock, timestamp });
              }
              batch.set(getDocRef('inventoryMovements', `TF-PT-${timestamp}-${ch.cleanCode}`), { id:`TF-PT-${timestamp}-${ch.cleanCode}`, date:tomaFisicaDate||getTodayDate(), itemId:ch.cleanCode, itemName:ch.ptDocs[0]?.desc||ch.cleanCode, type:ch.diff>0?'AJUSTE (POSITIVO)':'AJUSTE (NEGATIVO)', qty:Math.abs(ch.diff), cost:ch.ptDocs[0]?.cost||0, totalValue:Math.abs(ch.diff)*(ch.ptDocs[0]?.cost||0), reference:'TOMA FÍSICA', notes:'AJUSTE MASIVO PT', timestamp, user:appUser?.name||'Sistema' });
            }
          }
          await batch.commit();
          try {
            const tomaSnapshot = changes.map(ch=>({ id:ch.cleanCode||ch.pfId||ch.item?.id||'', desc:ch.ptDocs?.[0]?.desc||ch.item?.desc||(ch.fgDocs?.[0]?formatFGLabel(ch.fgDocs[0]):'—'), category:ch.kind==='inventory'?(ch.item?.category||'General'):'Productos Terminados', unit:ch.ptDocs?.[0]?.unit||ch.item?.unit||(ch.esTermo?'KG':'Millares'), sysStock:ch.sysStock??parseNum(ch.item?.stock||0), physCount:ch.newStock, diff:ch.diff, kind:ch.kind }));
            await addDoc(getColRef('tomasFisicas'), { fecha:getTodayDate(), fechaHora:new Date().toLocaleString('es-VE'), timestamp:Date.now(), realizadaPor:appUser?.name||'Sistema', username:appUser?.username||'', observaciones:'', totalItems:tomaSnapshot.length, totalAjustes:count, items:tomaSnapshot });
          } catch(e){ console.warn('Error guardando toma física:', e); }
          setPhysicalCounts({});
          setDialog({title:'✅ Toma Física Procesada', text:`${count} ajuste(s) aplicados.`, type:'alert'});
        } catch(e){ setDialog({title:'Error', text:e.message, type:'alert'}); }
      }
    });
  };

