        try { await deleteDoc(getDocRef('tomasFisicas', id)); setDialog({title:'Eliminado', text:'Registro de toma física eliminado.', type:'alert'}); } catch(e) { setDialog({title:'Error', text: e.message, type:'alert'}); }
