  const exportTomaFisicaExcelByRecord = (toma) => {
    const catColors = {'Materia Prima':'#2d5016','Pigmentos':'#7b3f00','Semielaborados':'#3730a3','Consumibles':'#1e40af','Herramientas':'#92400e','Tintas':'#6d28d9','Quimicos':'#065f46','Seguridad Industrial':'#7c3aed','Productos Terminados':'#065f46','En Proceso (WIP)':'#1e40af','General':'#374151'};
    const grouped = {};
    (toma.items||[]).forEach(it => { const cat = it.category||'General'; if(!grouped[cat]) grouped[cat]=[]; grouped[cat].push(it); });
    let rows = '';
    Object.keys(grouped).forEach(cat => {
      const color = catColors[cat]||'#374151';
      rows += `<tr><td colspan="6" style="background:${color};color:#fff;font-weight:bold;padding:6px;font-size:11px;">📦 ${cat.toUpperCase()}</td></tr>`;
      grouped[cat].forEach((it,i) => {
        const bg = i%2===1?'background:#f9f9f9':'';
        const diffColor = it.diff>0?'color:#166534':it.diff<0?'color:#991b1b':'color:#6b7280';
        rows += `<tr><td style="${bg}">${it.id}</td><td style="${bg}">${(it.desc||'').toUpperCase()}</td><td style="text-align:center;${bg}">${it.unit||'KG'}</td><td style="text-align:right;${bg}">${formatNum(it.sysStock)}</td><td style="text-align:right;${bg}">${formatNum(it.physCount)}</td><td style="text-align:right;font-weight:bold;${diffColor};${bg}">${it.diff>0?'+':''}${formatNum(it.diff)}</td></tr>`;
      });
    });
    const html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="utf-8"><style>body{font-family:Arial}table{border-collapse:collapse;width:100%}th,td{border:1px solid #555;padding:5px 8px;font-size:10px}th{background:#e8e8e8;font-weight:bold;text-align:center}</style></head><body>
    <div style="text-align:center;margin-bottom:16px"><h2 style="margin:2px 0;font-size:14px">SERVICIOS JIRET G&amp;B, C.A.</h2><p style="margin:1px 0;font-size:11px"><strong>RIF: J-412309374</strong> | Pto. La Cruz, Anzoategui</p><h3 style="margin:4px 0;font-size:13px">REPORTE DE TOMA FISICA DE INVENTARIO</h3><p style="font-size:11px"><strong>Fecha:</strong> ${toma.fecha} | <strong>Realizado por:</strong> ${toma.realizadaPor} | <strong>Ref.:</strong> TF-${String(toma.timestamp).slice(-6)}</p>${toma.observaciones?`<p style="font-size:10px;color:#555">Obs: ${toma.observaciones}</p>`:''}</div>
    <table><thead><tr><th style="width:12%">Codigo</th><th style="width:32%">Descripcion</th><th style="width:8%">Unidad</th><th style="width:13%">Stock Sistema</th><th style="width:13%">Conteo Fisico</th><th style="width:13%">Diferencia</th></tr></thead><tbody>${rows}</tbody></table>
    <div style="margin-top:40px;font-size:11px"><p><strong>Total items contados:</strong> ${toma.totalItems} | <strong>Ajustes aplicados:</strong> ${toma.totalAjustes}</p><br/><table style="width:100%;border:none"><tr><td style="border:none;width:50%"><strong>Realizado por:</strong> ${toma.realizadaPor}<br/><br/>Firma: _______________________<br/>Fecha: ${toma.fecha}</td><td style="border:none;width:50%"><strong>Supervisado por:</strong> _______________________<br/><br/>Firma: _______________________<br/>Fecha: _______________</td></tr></table></div></body></html>`;
    const blob = new Blob([html], {type:'application/vnd.ms-excel'});
    const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href=url; a.download=`TF_${toma.fecha}_${String(toma.timestamp).slice(-6)}.xls`; document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  // ============================================================================
  // LOGICA CONFIGURACIÓN / USUARIOS
  // ============================================================================
  const handleSaveUser = async (e) => {
    e.preventDefault();
    if (!newUserForm.username || !newUserForm.password) return setDialog({title:'Aviso', text:'Usuario y contraseña requeridos.', type:'alert'});
    const newUserId = newUserForm.username.toLowerCase().trim();
    try {
      const batch = writeBatch(db);
      // Si estamos editando Y el nombre de usuario cambió
      if (editingUserId && originalUsername && originalUsername !== newUserId) {
        const existingUserDoc = (systemUsers || []).find(u => u.username === newUserId);
        if (existingUserDoc) return setDialog({title: 'Error', text: `El usuario '${newUserId}' ya existe. Elija otro.`, type: 'alert'});
        // Borrar documento viejo
        batch.delete(getDocRef('users', originalUsername));
      }
      // Guardar documento con el ID correcto
      // IMPORTANTE: excluir el campo 'id' del objeto guardado para evitar conflictos
      const { id: _skipId, ...formToSave } = newUserForm;
      batch.set(getDocRef('users', newUserId), { ...formToSave, username: newUserId });
      await batch.commit();
      setNewUserForm(initialUserForm);
      setEditingUserId(null);
      setOriginalUsername(null);
      setDialog({title: 'Éxito', text: (editingUserId && originalUsername !== newUserId) ? 'Usuario actualizado y renombrado.' : 'Usuario guardado.', type: 'alert'});
    } catch(err) { setDialog({title: 'Error', text: err.message, type: 'alert'}); }
  };
  const startEditUser = (u) => {
    const defaultPerms = generateDefaultPermissions();
    // Fusionar permisos por defecto con los del usuario (asegura que módulos nuevos aparezcan en false)
    const mergedPerms = { ...defaultPerms, ...(u.permissions || {}) };
    const mergedPortales = { produccion:true, administracion:true, finanzas:true, contabilidad:true, configuracion_portal:true, ...(u.portales || {}) };
    setEditingUserId(u.username);
    setOriginalUsername(u.username);
    setNewUserForm({ ...u, permissions: mergedPerms, portales: mergedPortales });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };
  const handleDeleteUser = (usernameOrId) => {
    // Buscar el usuario real en la lista (por username o por id)
    const targetUser = (systemUsers || []).find(u => u.username === usernameOrId || u.id === usernameOrId);
    const targetUsername = targetUser?.username || usernameOrId;
    const targetDocId = targetUser?.id || targetUser?.username || usernameOrId;

    // No puede eliminar su propio usuario
    if (targetUsername === appUser?.username) {
      return setDialog({ title: 'Acción Denegada', text: 'No puedes eliminar tu propio usuario activo.', type: 'alert' });
    }
    // No puede eliminar el único administrador Master
    const masterUsers = (systemUsers || []).filter(u => u.role === 'Master');
    if ((targetUser?.role === 'Master') && masterUsers.length <= 1) {
      return setDialog({ title: 'Acción Denegada', text: 'No puedes eliminar el único administrador del sistema. Primero crea otro usuario Master.', type: 'alert' });
    }
    if (!targetUser) {
      return setDialog({ title: 'Error', text: `Usuario "${usernameOrId}" no encontrado.`, type: 'alert' });
    }
    setDialog({
      title: 'Eliminar Usuario',
      text: `¿Desea eliminar el acceso de "${targetUser.name || targetUsername}" (usuario: ${targetUsername})?`,
      type: 'confirm',
      onConfirm: async () => {
        try {
          await deleteDoc(getDocRef('users', targetDocId));
          setDialog({ title: '✅ Eliminado', text: `Usuario "${targetUsername}" eliminado correctamente.`, type: 'alert' });
        } catch(err) {
          setDialog({ title: 'Error', text: err.message, type: 'alert' });
        }
      }
    });
  };

  // ============================================================================
  // FIX 7: Corrección de datos de Productos Terminados (one-time, idempotent)
  // ============================================================================
  useEffect(() => {
    if (!appUser || appUser.role !== 'Master' || !finishedGoodsInventory.length) return;
    const runFix7 = async () => {
      try {
        let batchOps = [];
        const flush = async () => {
          if (!batchOps.length) return;
          const b = writeBatch(db);
          batchOps.forEach(op => op.type === 'delete' ? b.delete(op.ref) : b.update(op.ref, op.data));
          await b.commit(); batchOps = [];
        };
        for (const fg of finishedGoodsInventory) {
          const prod = (fg.producto || '').toUpperCase();
          // 1. Eliminar TODOS los registros con 9X14X6MIC en el nombre
          if (prod.includes('9X14X6MIC')) {
            batchOps.push({ type: 'delete', ref: getDocRef('finishedGoodsInventory', fg.id) });
            if (batchOps.length >= 400) await flush();
            continue;
          }
          // 2. Corregir 60X82X30MIC → nombre limpio, stock real 8.76, costo $287.21/Mill.
          if (prod.includes('60X82X30MIC') && !fg._fix7Applied) {
            batchOps.push({ type: 'update', ref: getDocRef('finishedGoodsInventory', fg.id), data: {
              producto: 'AFS GRIS 60X82X30MIC',
              millares: 8.76,
              kgProducidos: 0,
              costoUnitarioMillar: 287.21,
              costoUnitario: 287.21,
              tipoProducto: 'BOLSAS',
              _fix7Applied: true
            }});
            if (batchOps.length >= 400) await flush();
          }
        }
        await flush();
        // 3. Eliminar movimientos de Kardex con nombre corrupto del 60X82
        const badMovs = (invMovements||[]).filter(m => {
          const d = (m.itemDesc||'').toUpperCase();
          return d.includes('60X82X30MIC') && (d.includes('60X82X30MIC - AFS') || d.includes('AFS GRIS 60X82X30MIC - 60X82'));
        });
        if (badMovs.length > 0) {
          const bm = writeBatch(db);
          badMovs.forEach(m => bm.delete(getDocRef('inventoryMovements', m.id)));
          await bm.commit();
        }
      } catch(e) { console.warn('Fix7:', e.message); }
    };
    runFix7();
  }, [appUser, finishedGoodsInventory.length]);

  // ============================================================================
  // FG PRODUCT EDIT HANDLER
  // ============================================================================
  const handleSaveFGEdit = async () => {
    if(!editingFG) return;
    try {
      const newNombre = fgEditForm.producto.toUpperCase().trim() || editingFG.producto;
      const esTermo = editingFG.tipoProducto === 'TERMOENCOGIBLE';
      const grp = editingFG._group;
      const lotesToUpdate = grp ? grp.lotes : [editingFG];
      const batch = writeBatch(db);
      for(const fg of lotesToUpdate) {
        const isFirst = fg.id === lotesToUpdate[0].id;
        // FIX: save both producto AND categoria so description persists correctly
        const upd = { producto: newNombre, categoria: newNombre };
        const newCostoMillar = fgEditForm.costoUnitarioMillar !== '' ? parseNum(fgEditForm.costoUnitarioMillar) : null;
        const newCostoKg = fgEditForm.costoUnitario !== '' ? parseNum(fgEditForm.costoUnitario) : null;
        if(newCostoMillar !== null) upd.costoUnitarioMillar = newCostoMillar;
        if(newCostoKg !== null) upd.costoUnitario = newCostoKg;
        if(isFirst) {
          if(!esTermo && fgEditForm.millares !== '') {
            const newTotal = parseNum(fgEditForm.millares);
            upd.millares = newTotal;
            upd.millaresOrigen = Math.max(newTotal, parseNum(fg.millaresOrigen || 0));
          }
          if(esTermo && fgEditForm.kgProducidos !== '') {
            const newTotal = parseNum(fgEditForm.kgProducidos);
            upd.kgProducidos = newTotal;
            upd.kgProducidosOrigen = Math.max(newTotal, parseNum(fg.kgProducidosOrigen || 0));
          }
        } else {
          upd.millares = 0;
          upd.kgProducidos = 0;
        }
        batch.update(getDocRef('finishedGoodsInventory', fg.id), upd);
      }
      await batch.commit();
      setEditingFG(null);
      setDialog({ title: '✅ Actualizado', text: `"${newNombre}" guardado correctamente en todos los lotes.`, type: 'alert' });
    } catch(err) { setDialog({ title: 'Error al guardar', text: err.message, type: 'alert' }); }
  };


  // ============================================================================
  // HANDLER: EDITAR STOCK/COSTO DE PRODUCTO EN ALMACÉN ESPECÍFICO
  // Actualiza directamente el documento Firebase del almacén y registra movimiento
  // ============================================================================
  // ============================================================================
  // SINCRONIZAR COSTOS — equipara el costo promedio de cada producto en todos sus almacenes
  // ============================================================================
  const handleSyncAllCosts = async () => {
    setDialog({ title: 'Sincronizar Costos', text: '¿Desea actualizar el costo unitario de TODOS los productos en todos los almacenes para que coincidan con el costo promedio ponderado mostrado en Inventario General? Esta acción es irreversible.', type: 'confirm', onConfirm: async () => {
      try {
        // Group all inventory docs by cleanId, compute weighted average
        const groups = {};
        for (const i of (inventory||[])) {
          const cleanId = i.displayId || (i.id||'').split('___')[0];
          if (!groups[cleanId]) groups[cleanId] = { totalVal: 0, totalStock: 0, docs: [] };
          const stk = parseNum(i.stock||0);
          const cst = parseNum(i.cost||0);
          groups[cleanId].totalVal += stk * cst;
          groups[cleanId].totalStock += stk;
          groups[cleanId].docs.push(i);
        }
        // Update all docs with the weighted average cost
        const batchSize = 400;
        let ops = [];
        for (const [cleanId, g] of Object.entries(groups)) {
          if (g.docs.length <= 1) continue; // single warehouse: already consistent
          // FIX 8: Use the cost from the most recently updated document (direct substitution)
          // FIX 2: Use weighted average = the cost Inventario General shows
          // This way after sync, Gestión de Almacenes matches exactly Inventario General
          const avgCost = g.totalStock > 0 ? g.totalVal / g.totalStock : (g.docs[0]?.cost || 0);
          if (avgCost <= 0) continue;
          for (const doc of g.docs) {
            const docCost = parseNum(doc.cost||0);
            if (Math.abs(docCost - avgCost) > 0.001) ops.push({ id: doc.id, cost: avgCost });
          }
        }
        // Write in batches
        let count = 0;
        for (let i = 0; i < ops.length; i += batchSize) {
          const chunk = ops.slice(i, i + batchSize);
          const b = writeBatch(db);
          chunk.forEach(op => b.set(getDocRef('inventory', op.id), { cost: op.cost }, { merge: true }));
          await b.commit();
          count += chunk.length;
        }
        if (count === 0) {
          setDialog({ title: 'ℹ️ Sin cambios', text: 'Todos los almacenes ya tienen el mismo costo. No hubo nada que actualizar.', type: 'alert' });
        } else {
          setDialog({ title: '✅ Costos Igualados', text: `${count} documento(s) actualizados. Todos los almacenes ahora usan el mismo costo por producto.`, type: 'alert' });
        }
      } catch(err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
    }});
  };

  const handleSaveAlmacenItem = async () => {
    if (!editingAlmacenItem) return;
    const newStock = parseNum(almacenEditForm.stock);
    const newCost  = parseNum(almacenEditForm.cost);
    const prevStock = parseNum(editingAlmacenItem.stock || 0);
    const cleanIdEdit = editingAlmacenItem.displayId || (editingAlmacenItem.id||'').split('___')[0];
    const almacenEdit = editingAlmacenItem.almacen || 'ALMACEN ZI';
    // Use _realId (set during grouping) — this is the actual Firebase document ID
    const realDocId = editingAlmacenItem._realId || (() => {
      const found = (inventory||[]).find(i => {
        const cid = i.displayId || (i.id||'').split('___')[0];
        return cid === cleanIdEdit && (i.almacen || 'ALMACEN ZI') === almacenEdit;
      });
      return found?.id || (cleanIdEdit + '___' + almacenEdit.replace(/\s+/g, '-'));
    })();
    try {
      const hasCostChange = almacenEditForm.cost !== '';
      const hasStockChange = almacenEditForm.stock !== '';
      if (!hasCostChange && !hasStockChange) return;
      // FIX 8: Cost = DIRECT SUBSTITUTION to ALL warehouses (no averaging, no division)
      // Stock = only the specific warehouse being edited
      // DESC/SUBCATEGORY: propagate to ALL warehouse docs via batch (Fix Issue #2)
      const hasDescChange = almacenEditForm.desc && almacenEditForm.desc !== editingAlmacenItem.desc;
      const hasSubcatChange = almacenEditForm.subcategory && almacenEditForm.subcategory !== (editingAlmacenItem.subcategory||'');
      if(hasDescChange || hasSubcatChange) {
        // Propagate to all warehouse docs with same displayId
        const allWarehouseDocs = (inventory||[]).filter(i=>{
          const cid = i.displayId||(i.id||'').split('___')[0];
          return cid === cleanIdEdit;
        });
        if(allWarehouseDocs.length > 1) {
          const batchProp = writeBatch(db);
          allWarehouseDocs.forEach(wDoc=>{
            const updates = {};
            if(hasDescChange) updates.desc = almacenEditForm.desc.toUpperCase();
            if(hasSubcatChange) updates.subcategory = almacenEditForm.subcategory;
            batchProp.update(getDocRef('inventory', wDoc.id), updates);
          });
          await batchProp.commit();
        }
      }
      if (hasCostChange) {
        const allDocs = (inventory||[]).filter(i => (i.displayId || (i.id||'').split('___')[0]) === cleanIdEdit);
        if (allDocs.length > 0) {
          const b = writeBatch(db);
          allDocs.forEach(d => {
            const upd = { cost: newCost, timestamp: Date.now() };
            if (almacenEditForm.desc) upd.desc = almacenEditForm.desc.toUpperCase();
            if (almacenEditForm.subcategory !== undefined) upd.subcategory = almacenEditForm.subcategory;
            if (d.id === realDocId && hasStockChange) upd.stock = newStock;
            b.set(getDocRef('inventory', d.id), upd, { merge: true });
          });
          await b.commit();
        } else {
          // No existing docs — create/update the specific warehouse doc
          const upd = { cost: newCost, timestamp: Date.now() };
          if (hasStockChange) upd.stock = newStock;
          await setDoc(getDocRef('inventory', realDocId), upd, { merge: true });
        }
      } else {
        // Only stock — update just this warehouse
        await setDoc(getDocRef('inventory', realDocId), { stock: newStock, timestamp: Date.now() }, { merge: true });
      }
      // Kardex entry for stock change
      const diff = hasStockChange ? newStock - prevStock : 0;
      if (Math.abs(diff) > 0.001) {
        await addDoc(getColRef('inventoryMovements'), {
          itemId: realDocId, itemDesc: editingAlmacenItem.desc, almacen: almacenEdit,
          type: diff > 0 ? 'ENTRADA' : 'SALIDA', qty: Math.abs(diff),
          unitCost: hasCostChange ? newCost : parseNum(editingAlmacenItem.cost||0),
          totalValue: Math.abs(diff) * (hasCostChange ? newCost : parseNum(editingAlmacenItem.cost||0)),
          previousStock: prevStock, newStock,
          docRef: 'AJUSTE MANUAL ALMACÉN', notes: `Gestión de Almacenes — ${almacenEdit}`,
          date: getTodayDate(), user: appUser?.name || 'Admin', timestamp: Date.now()
        });
      }
      setEditingAlmacenItem(null);
      setDialog({ title: '✅ Actualizado', text: `${cleanIdEdit}: ${hasCostChange?`costo $${formatNum(newCost)} aplicado en TODOS los almacenes. `:''}${hasStockChange?`stock ${formatNum(newStock)} en ${almacenEdit}.`:''}`, type: 'alert' });
    } catch (err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };;

  // ============================================================================
  // IMPORTAR INVENTARIO CONSOLIDADO DESDE EXCEL (datos precargados)
  // ============================================================================

  // ── REVERTIR IMPORTACIÓN CONSOLIDADA ─────────────────────────────────────────
  const handleRevertImport = () => {
    // Elimina artículos de CUALQUIER importación consolidada:
    // - Marcados con _importSource (importaciones recientes)
    // - ID con ___ALMACEN- (patrón de todas las importaciones del consolidado)
    const importedItems = (inventory || []).filter(i =>
      i._importSource === 'CONSOLIDADO_INV' ||
      i._importSource === 'CONSOLIDADO_PT' ||
      (typeof i.id === 'string' && i.id.includes('___ALMACEN-'))
    );
    if (importedItems.length === 0) {
      setDialog({
        title: 'Sin importación reciente',
        text: 'No se encontraron artículos del último import consolidado de PT.\nSi acabas de importar y esto persiste, recarga la página.',
        type: 'alert'
      });
      return;
    }
    const byAlm = importedItems.reduce((a,i)=>{ const k=i.almacen||'—'; a[k]=(a[k]||0)+1; return a; },{});
    const resumen = Object.entries(byAlm).map(([k,v])=>`• ${k}: ${v}`).join('\n');
    setDialog({
      title: `Revertir importación — ${importedItems.length} artículos`,
      text: `Se eliminarán los ${importedItems.length} artículos creados por importaciones del consolidado (incluye importaciones previas sin etiquetar).\n\n${resumen}\n\n¿Continuar?`,
      type: 'confirm',
      onConfirm: async () => {
        try {
          const batchSize = 400;
          let deleted = 0;
          for (let i = 0; i < importedItems.length; i += batchSize) {
            const chunk = importedItems.slice(i, i + batchSize);
            const batch = writeBatch(db);
            for (const item of chunk) {
              batch.delete(getDocRef('inventory', item.id));
              deleted++;
            }
            await batch.commit();
          }
          setDialog({ title: '✅ Revertido correctamente', text: `${deleted} artículos PT eliminados. Materia Prima y demás intactos.`, type: 'alert' });
        } catch(err) {
          setDialog({ title: 'Error al revertir', text: err.message, type: 'alert' });
        }
      }
    });
  };

  // ── IMPORTAR INVENTARIO CONSOLIDADO DESDE EXCEL ──────────────────────────────
  const handleImportConsolidatedInventory = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.xlsx,.xls';
    input.onchange = async (e) => {
      const file = e.target.files?.[0];
      if (!file) return;
      try {
        const arrayBuffer = await new Promise((res,rej)=>{ const r=new FileReader(); r.onload=ev=>res(ev.target.result); r.onerror=rej; r.readAsArrayBuffer(file); });
        let XLSX; try{XLSX=window.XLSX;}catch(_){}
        if (!XLSX) {
          await new Promise((res,rej)=>{ const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'; s.onload=res; s.onerror=rej; document.head.appendChild(s); });
          XLSX=window.XLSX;
        }
        const wb = XLSX.read(arrayBuffer,{type:'array'});
        const ws = wb.Sheets[wb.SheetNames[0]];
        const rows = XLSX.utils.sheet_to_json(ws,{header:1,defval:null});

        // ── Detectar columnas dinámicamente leyendo la cabecera ──────────────
        // Buscar la fila cabecera: la que tiene col0='CODIGOS' o col5='ALMACEN ZI'
        let headerRowIdx = -1;
        for (let i=0; i<Math.min(10,rows.length); i++) {
          const r = rows[i];
          const c0 = String(r[0]||'').toUpperCase();
          const c5 = String(r[5]||'').toUpperCase();
          if (c0 === 'CODIGOS' || c5.startsWith('ALMACEN')) { headerRowIdx = i; break; }
        }
        if (headerRowIdx < 0) {
          setDialog({title:'Error de formato',text:'No se encontró la fila de encabezados. Verifica que el archivo sea el consolidado.',type:'alert'});
          return;
        }
        const headerRow = rows[headerRowIdx];

        // Detectar qué columna corresponde a cada almacén
        // La cabecera tiene: col0=CODIGOS, col1=PRODUCTOS, col2=CATEGORIA, col3=U.M, col4=COSTO
        // Luego pares: ALMACEN XX, [Valor], ALMACEN YY, [Valor], ...
        const almCols = [];
        for (let col=5; col<headerRow.length; col++) {
          const val = String(headerRow[col]||'').toUpperCase().trim();
          if (val.startsWith('ALMACEN') && !val.includes('TOTAL')) {
            // El nombre del almacen es tal cual está en la cabecera
            const almName = String(headerRow[col]).trim();
            const suffix  = almName.replace(/\s+/g,'-'); // ALMACEN ZI → ALMACEN-ZI
            almCols.push({col, field: almName, suffix});
          }
        }
        if (almCols.length === 0) {
          setDialog({title:'Error',text:'No se detectaron columnas de almacén en el archivo.',type:'alert'});
          return;
        }

        // Mapeo subcategoría → categoría principal
        const CAT_MAP = {
          'Bolsas Plásticas':'Productos Terminados','Cintas':'Productos Terminados',
          'Dispensadores':'Productos Terminados','Papel Kraft':'Productos Terminados',
          'Stretch Film':'Productos Terminados','Termoencogibles':'Productos Terminados',
          'Materia Prima':'Materia Prima','Quimicos':'Quimicos',
          'Pigmento':'Pigmento','Pigmentos':'Pigmento','Tintas':'Tintas',
          'Semielaborados':'Semielaborado','Semielaborado':'Semielaborado',
        };

        // Filas que deben ignorarse
        const SKIP = ['CODIGOS','TOTAL','SERVICIOS JIRET','RIF:','  ▸','ALMACEN','RESUMEN','VALOR INVENTARIO'];
        const parseN = v => { if(!v||v==='—') return 0; if(typeof v==='number') return v; return parseFloat(String(v).replace(/[$,\s]/g,''))||0; };

        const items = []; const usedIds = new Set(); let skipped = 0;

        for (let ri = headerRowIdx+1; ri < rows.length; ri++) {
          const row = rows[ri];
          const code = row[0];
          if (!code) continue;
          const codeStr = String(code).trim();
          if (codeStr.length < 2) continue;
          // Saltar filas de encabezado, totales, resúmenes y similares
          if (SKIP.some(p => codeStr.toUpperCase().startsWith(p.toUpperCase()))) continue;
          // Saltar filas donde el código parece ser un nombre de almacén o ciudad
          if (/^(Almac[eé]n|Barquisimeto|Maracay|Materia Prima|Semielaborado|Quimico|Pigmento|Tintas?|ZI|C2|MCY|BQTO|Consignac)/i.test(codeStr)) continue;

          const desc   = String(row[1]||'').trim().toUpperCase();
          const subcat = String(row[2]||'').trim();
          const um     = String(row[3]||'UND').trim().toUpperCase();
          const cost   = parseN(row[4]);
          const cat    = CAT_MAP[subcat] || subcat || 'Productos Terminados';
          const cleanCode = codeStr.replace(/\//g,'-');
          // Normalizar código: quitar ceros finales en decimales (0.030 → 0.03)
          const normalizeCode = c => c.replace(/(\.\d*?)0+(?=___|\b|-)/g,'$1').replace(/\.(?=___|\b|-)/g,'');
          const normClean = normalizeCode(cleanCode);

          // Verificar si ya existe en el sistema con el mismo código (evitar duplicados)
          const alreadyExists = (inventory||[]).some(inv => {
            const invId    = normalizeCode((inv.displayId || (inv.id||'').split('___')[0]));
            const invIdRaw = (inv.displayId || (inv.id||'').split('___')[0]);
            return invId === normClean || invIdRaw === cleanCode || invIdRaw === normClean;
          });
          if (alreadyExists) { skipped++; continue; }

          const stocks = almCols.map(a=>({...a, stock:parseN(row[a.col])}));
          const totalSt = stocks.reduce((s,a)=>s+a.stock,0);

          if (totalSt > 0) {
            for (const {suffix, field, stock} of stocks) {
              if (stock <= 0) continue;
              let docId = `${cleanCode}___${suffix}`;
              if (usedIds.has(docId)) { docId = `${cleanCode}-${subcat.substring(0,3).toUpperCase()}___${suffix}`; }
              usedIds.add(docId);
              items.push({id:docId, displayId:cleanCode, desc, category:cat, subcategory:subcat, unit:um, cost, stock, almacen:field, activo:true});
            }
          } else {
            const firstAlm = almCols[0];
            let docId = `${cleanCode}___${firstAlm.suffix}`;
            if (usedIds.has(docId)) { docId = `${cleanCode}-${subcat.substring(0,3).toUpperCase()}___${firstAlm.suffix}`; }
            usedIds.add(docId);
            items.push({id:docId, displayId:cleanCode, desc, category:cat, subcategory:subcat, unit:um, cost, stock:0, almacen:firstAlm.field, activo:true});
          }
        }

        if (!items.length) {
          setDialog({title:'Aviso',text:'No se encontraron artículos. Verifica el archivo.',type:'alert'});
          return;
        }

        const byCat = {}; const byAlm = {};
        items.forEach(i=>{ byCat[i.category]=(byCat[i.category]||0)+1; byAlm[i.almacen]=(byAlm[i.almacen]||0)+1; });
        const resCat = Object.entries(byCat).map(([k,v])=>`• ${k}: ${v}`).join('\n');
        const resAlm = Object.entries(byAlm).map(([k,v])=>`• ${k}: ${v}`).join('\n');
        const almDetected = almCols.map(a=>a.field).join(' · ');

        setDialog({
          title:`📦 Importar ${items.length} artículos`,
          text:`Archivo: ${file.name}\nAlmacenes detectados: ${almDetected}${skipped>0?`\n⚠️ ${skipped} artículo(s) omitidos por ya existir en el sistema`:''}\n\nPOR CATEGORÍA:\n${resCat}\n\nPOR ALMACÉN:\n${resAlm}\n\n¿Continuar?`,
          type:'confirm',
          onConfirm: async () => {
            try {
              let created=0, updated=0;
              for (let i=0; i<items.length; i+=400) {
                const chunk=items.slice(i,i+400);
                const batch=writeBatch(db);
                for (const item of chunk) {
                  const ref=getDocRef('inventory',item.id);
                  const existing=(inventory||[]).find(x=>x.id===item.id);
                  if (existing) {
                    batch.update(ref,{stock:item.stock,cost:item.cost,desc:item.desc,category:item.category,subcategory:item.subcategory,displayId:item.displayId,unit:item.unit,almacen:item.almacen,activo:true,_importSource:'CONSOLIDADO_INV',updatedAt:Date.now()});
                    updated++;
                  } else {
                    batch.set(ref,{id:item.id,displayId:item.displayId,desc:item.desc,category:item.category,subcategory:item.subcategory,unit:item.unit,cost:item.cost,stock:item.stock,almacen:item.almacen,activo:true,minStock:0,_importSource:'CONSOLIDADO_INV',timestamp:Date.now()});
                    created++;
                  }
                }
                await batch.commit();
              }
              setDialog({title:'✅ Importación Completa',text:`${created} creados · ${updated} actualizados\nTotal: ${created+updated} artículos en Firebase.`,type:'alert'});
            } catch(err) { setDialog({title:'Error',text:err.message,type:'alert'}); }
          }
        });
      } catch(err) { setDialog({title:'Error al leer archivo',text:err.message,type:'alert'}); }
    };
    input.click();
  };

  // ============================================================================
  // GESTIÓN DE DEPÓSITOS / ALMACENES (CRUD Firebase)
  // ============================================================================
  const handleSaveDeposito = async () => {
    const nombre = depositoForm.nombre.toUpperCase().trim();
    if (!nombre) return setDialog({ title: 'Aviso', text: 'El nombre del depósito es obligatorio.', type: 'alert' });
    try {
      if (depositoForm.editId) {
        // FIX 3: Find the actual Firestore document by its nombre field (editId = old name)
        // Query the depositos collection for the document with the old name
        const { getDocs, query, where } = await import('firebase/firestore');
        const snap = await getDocs(query(getColRef('depositos'), where('nombre', '==', depositoForm.editId)));
        if (snap.empty) {
          // Document doesn't exist yet — create it with the new name (migration from hardcoded array)
          const newId = `DEP-${Date.now()}`;
          await setDoc(getDocRef('depositos', newId), { nombre, estado: 'activo', id: newId, timestamp: Date.now() });
        } else {
          // Update existing doc
          for (const docSnap of snap.docs) {
            await import('firebase/firestore').then(({updateDoc}) => updateDoc(docSnap.ref, { nombre }));
          }
        }
        setDialog({ title: '✅ Actualizado', text: `Depósito renombrado a "${nombre}".`, type: 'alert' });
      } else {
        const newId = `DEP-${Date.now()}`;
        await setDoc(getDocRef('depositos', newId), { nombre, estado: 'activo', id: newId, timestamp: Date.now() });
        setDialog({ title: '✅ Creado', text: `Depósito "${nombre}" creado.`, type: 'alert' });
      }
      setDepositoForm({ nombre: '', editId: null });
      setShowDepositoModal(false);
    } catch (err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };
  const handleDeleteDeposito = async (nombre) => {
    setDialog({ title: 'Eliminar Depósito', text: `¿Eliminar el depósito "${nombre}"? Los artículos asignados a él no se borran.`, type: 'confirm',
      onConfirm: async () => {
        try {
          // Buscar el doc por nombre y eliminarlo
          const snap = await import('firebase/firestore').then(({getDocs, query, where}) =>
            getDocs(query(getColRef('depositos'), where('nombre','==',nombre))));
          for (const d of snap.docs) await deleteDoc(getDocRef('depositos', d.id));
          setDialog({ title: '✅ Eliminado', text: `Depósito "${nombre}" eliminado.`, type: 'alert' });
        } catch(err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
      }
    });
  };

  // ============================================================================
  // CONTROL ALIMENTARIO — ÓRDENES DE SALIDA (con transacción atómica)
  // ============================================================================
  const handleAlimentarioSalida = async () => {
    const { productoId, cantidad, concepto, fecha, solicitante } = alimentarioForm;
    if (!productoId || !cantidad || parseNum(cantidad) <= 0)
      return setDialog({ title: 'Aviso', text: 'Seleccione producto e ingrese cantidad válida.', type: 'alert' });
    const cantNum = parseNum(cantidad);
    try {
      // runTransaction asegura atomicidad: stock y Kardex se actualizan juntos
      const { runTransaction: runTx, serverTimestamp, collection: fbCol, doc: fbDoc } = await import('firebase/firestore');
      const prodRef = getDocRef('inventario_alimentario', productoId);
      await runTx(db, async (tx) => {
        const prodSnap = await tx.get(prodRef);
        if (!prodSnap.exists()) throw new Error('Producto no encontrado en inventario alimentario.');
        const stockActual = parseNum(prodSnap.data().stock || 0);
        if (stockActual < cantNum) throw new Error(`Stock insuficiente. Disponible: ${formatNum(stockActual)}`);
        const nuevoStock = stockActual - cantNum;
        // 1. Descuenta stock
        tx.update(prodRef, { stock: nuevoStock });
        // 2. Registra movimiento en sub-colección (Kardex)
        const movRef = fbDoc(fbCol(db, `inventario_alimentario/${productoId}/movimientos`));
        tx.set(movRef, {
          tipo: 'SALIDA', concepto: concepto || 'Orden de Salida',
          cantidad: cantNum, fecha: fecha || getTodayDate(),
          solicitante: solicitante || appUser?.name || '—',
          saldoAntes: stockActual, saldoDespues: nuevoStock,
          user: appUser?.name || '—', timestamp: Date.now()
        });
      });
      setAlimentarioForm({ productoId: '', cantidad: '', concepto: 'Orden de Salida Mantenimiento', fecha: getTodayDate(), solicitante: '' });
      setShowAlimentarioForm(false);
      setDialog({ title: '✅ Salida Registrada', text: `Salida de ${formatNum(cantNum)} unidades registrada con Kardex actualizado automáticamente.`, type: 'alert' });
    } catch (err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };

  const handleAlimentarioNuevoItem = async () => {
    const { nombre, unidad, stock, costo } = alimentarioNewItem;
    if (!nombre) return setDialog({ title: 'Aviso', text: 'Ingrese el nombre del producto.', type: 'alert' });
    try {
      const newId = `ALI-${Date.now()}`;
      await setDoc(getDocRef('inventario_alimentario', newId), {
        id: newId, nombre: nombre.toUpperCase(), unidad: unidad || 'UND',
        stock: parseNum(stock), costo: parseNum(costo),
        timestamp: Date.now(), user: appUser?.name || 'Admin'
      });
      setAlimentarioNewItem({ nombre: '', unidad: 'UND', stock: '', costo: '' });
      setShowAlimentarioNewItem(false);
      setDialog({ title: '✅ Producto creado', text: `"${nombre.toUpperCase()}" añadido al inventario alimentario.`, type: 'alert' });
    } catch (err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };

  // ============================================================================
  // LÓGICA TRASLADOS ENTRE ALMACENES
  // ============================================================================
  const handleSaveTraslado = async () => {
    const { almacenOrigen, almacenDestino, date, notes } = trasladoForm;
    if (!almacenOrigen || !almacenDestino) return setDialog({ title: 'Seleccione almacenes', text: `Por favor seleccione ambos almacenes en el formulario.\nActual → Origen: "${almacenOrigen||'sin seleccionar'}" | Destino: "${almacenDestino||'sin seleccionar'}"`, type: 'alert' });
    if (almacenOrigen === almacenDestino) return setDialog({ title: 'Aviso', text: 'El almacén origen y destino deben ser diferentes.', type: 'alert' });
    if (!trasladoItems.length) return setDialog({ title: 'Aviso', text: 'Agregue al menos un artículo al traslado.', type: 'alert' });

    try {
      const batch = writeBatch(db);
      const ts = Date.now();
      const itemsDesc = [];

      for (let idx = 0; idx < trasladoItems.length; idx++) {
        const { cleanCode, qty, unit, desc, stockOrigen: stockOrig } = trasladoItems[idx];
        const cantQty = parseNum(qty);
        if (cantQty <= 0) continue;

        const allDocs = (inventory||[]).filter(i => {
          const cc = (i.displayId||(i.id||'').split('___')[0]).replace(/-RESTORE$/i,'').replace(/-BACKUP$/i,'').replace(/_inv$/i,'').replace(/-COPY\d*$/i,'').toUpperCase();
          return cc === cleanCode.toUpperCase();
        });
        if(!allDocs.length) continue;
        const repDoc = allDocs[0];

        // ── Determinar stock real en almacén origen (acepta almacen field O warehouses map) ──
        const origenDoc = allDocs.find(i => (i.almacen||'').toUpperCase() === almacenOrigen.toUpperCase());
        // También checar si algún doc tiene el almacenOrigen en su warehouses map
        const origenDocMap = !origenDoc ? allDocs.find(i => parseNum((i.warehouses||{})[almacenOrigen]||0)>0) : null;

        const stockOrigen = origenDoc ? parseNum(origenDoc.stock||0) : (origenDocMap ? parseNum((origenDocMap.warehouses||{})[almacenOrigen]||0) : 0);
        if (cantQty > stockOrigen + 0.001) continue; // skip if insufficient stock

        const t = ts + idx * 2;

        // ── Descontar del ORIGEN ──
        if (origenDoc) {
          batch.update(getDocRef('inventory', origenDoc.id), { stock: Math.max(0, stockOrigen - cantQty), timestamp: t });
        } else if (origenDocMap) {
          const newWH = {...(origenDocMap.warehouses||{})};
          newWH[almacenOrigen] = Math.max(0, parseNum(newWH[almacenOrigen]||0) - cantQty);
          batch.update(getDocRef('inventory', origenDocMap.id), { warehouses: newWH, timestamp: t });
        }

        // ── Sumar al DESTINO ──
        const destinoDoc = allDocs.find(i => (i.almacen||'').toUpperCase() === almacenDestino.toUpperCase());
        const destinoDocMap = !destinoDoc ? allDocs.find(i => Object.prototype.hasOwnProperty.call(i.warehouses||{}, almacenDestino)) : null;
        if (destinoDoc) {
          batch.update(getDocRef('inventory', destinoDoc.id), { stock: parseNum(destinoDoc.stock||0) + cantQty, timestamp: t + 1 });
        } else if (destinoDocMap) {
          const newWH2 = {...(destinoDocMap.warehouses||{})};
          newWH2[almacenDestino] = parseNum(newWH2[almacenDestino]||0) + cantQty;
          batch.update(getDocRef('inventory', destinoDocMap.id), { warehouses: newWH2, timestamp: t + 1 });
        } else {
          // Crear nuevo doc para el almacén destino
          const newDocId = `${cleanCode}___${almacenDestino.replace(/\s+/g,'-')}`;
          batch.set(getDocRef('inventory', newDocId), {
            id: newDocId, displayId: cleanCode, desc: repDoc.desc,
            category: repDoc.category, subcategory: repDoc.subcategory||'',
            unit: repDoc.unit, cost: repDoc.cost, stock: cantQty,
            almacen: almacenDestino, activo: true, timestamp: t + 1
          });
        }
        // Kardex
        const movBase = { itemId: cleanCode, itemName: repDoc.desc, qty: cantQty, unitCost: repDoc.cost, totalValue: cantQty*(repDoc.cost||0), date, reference: 'TRASLADO', notes: `TRASLADO: ${almacenOrigen} → ${almacenDestino}${notes?' | '+notes.toUpperCase():''}`, user: appUser?.name||'Admin' };
        batch.set(getDocRef('inventoryMovements', `TSAL-${t}`), { ...movBase, id: `TSAL-${t}`, type: 'SALIDA_TRASLADO', almacen: almacenOrigen, almacenDestino, timestamp: t });
        batch.set(getDocRef('inventoryMovements', `TENT-${t+1}`), { ...movBase, id: `TENT-${t+1}`, type: 'ENTRADA_TRASLADO', almacen: almacenDestino, almacenOrigen, timestamp: t + 1 });
        itemsDesc.push(`${cleanCode}: ${formatNum(cantQty)} ${unit}`);
      }

      await batch.commit();
      setTrasladoForm(initialTrasladoForm); setTrasladoItems([]);
      setShowTrasladoModal(false); setTrasladoSearch('');
      setDialog({ title: '✅ Traslado Registrado', text: `${itemsDesc.length} artículo(s) trasladados de ${almacenOrigen} → ${almacenDestino}:\n${itemsDesc.join('\n')}`, type: 'alert' });
    } catch (err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };

  // ============================================================================
  // LOGICA INVENTARIO Y COSTO PROMEDIO
  // ============================================================================
  // Toggle activo/inactivo for all docs of a given cleanCode
  const handleToggleActivo = async (cleanCode, currentActivo) => {
    const newActivo = !currentActivo;
    const allDocs = (inventory||[]).filter(i => {
      const cc = (i.displayId||(i.id||'').split('___')[0]).replace(/-RESTORE$/i,'').replace(/-BACKUP$/i,'').replace(/_inv$/i,'').trim();
      return cc === cleanCode;
    });
    try {
      const b = writeBatch(db);
      allDocs.forEach(d => b.update(getDocRef('inventory', d.id), { activo: newActivo, timestamp: Date.now() }));
      await b.commit();
    } catch(err) {
      setDialog({ title: 'Error', text: err.message, type: 'alert' });
    }
  };

  const handleSaveInvItem = async (e) => {
    e.preventDefault();
    if (!newInvItemForm.id || !newInvItemForm.desc) return setDialog({ title: 'Aviso', text: 'Código obligatorio.', type: 'alert' });
    const itemId  = newInvItemForm.id.toUpperCase().trim();
    const newCost = parseNum(newInvItemForm.cost);
    const stockPerAlmacen = newInvItemForm.stockPerAlmacen || {};
    const hasPerWarehouse = Object.values(stockPerAlmacen).some(v => parseNum(v) > 0);

    try {
      if (hasPerWarehouse) {
        // ── MULTI-WAREHOUSE SAVE ──
        // REGLA: newCost (lo que el usuario ingresó) va EXACTO a TODOS los almacenes.
        // Sin cálculos, sin promedios. Stock solo en el almacén específico ingresado.
        const isNewItem = !editingInvId || editingInvId === null;
        const b = writeBatch(db);
        let docsAffected = 0;
        const almacenesConStock = [];
        for (const alm of depositos) {
          const docId = itemId + '___' + alm.replace(/\s+/g, '-');
          const hasStockEntry = stockPerAlmacen[alm] !== undefined && stockPerAlmacen[alm] !== '';
          const stk = hasStockEntry ? parseNum(stockPerAlmacen[alm]) : null;
          const existingDoc = (inventory||[]).find(i => i.id === docId);
          if (hasStockEntry) {
            // Update this warehouse with the entered stock + EXACT cost
            b.set(getDocRef('inventory', docId), {
              id: docId, displayId: itemId, almacen: alm,
              desc: newInvItemForm.desc.toUpperCase(),
              category: newInvItemForm.category || 'Materia Prima',
              subcategory: newInvItemForm.subcategory || '',
              unit: newInvItemForm.unit || 'kg',
              cost: newCost, stock: stk,
              activo: true, minStock: parseNum(newInvItemForm.minStock||0),
              timestamp: Date.now()
            }, { merge: true });
            if (stk > 0) almacenesConStock.push({ alm, stk, docId });
            docsAffected++;
          } else if (existingDoc && newCost > 0) {
            // No stock entered for this warehouse — just update the cost
            b.set(getDocRef('inventory', docId), { cost: newCost, timestamp: Date.now() }, { merge: true });
            docsAffected++;
          }
        }
        await b.commit();
        // Kardex entries only for new items (not for edits)
        if (isNewItem && almacenesConStock.length > 0) {
          for (const { alm, stk, docId } of almacenesConStock) {
            if (stk <= 0) continue;
            await addDoc(getColRef('inventoryMovements'), {
              itemId: docId, itemDesc: newInvItemForm.desc.toUpperCase(), almacen: alm,
              type: 'ENTRADA_INICIAL', qty: stk, unitCost: newCost, totalValue: stk * newCost,
              previousStock: 0, newStock: stk,
              docRef: 'INVENTARIO INICIAL', notes: 'Carga inicial multi-almacén',
              date: getTodayDate(), user: appUser?.name || 'Admin', timestamp: Date.now()
            });
          }
        }
        setNewInvItemForm(initialInvItemForm); setEditingInvId(null);
        setDialog({
          title: '✅ Guardado',
          text: `${itemId}: costo $${formatNum(newCost)} guardado en ${docsAffected} almacén(es). El promedio ponderado solo cambia al hacer Entradas con costos diferentes.`,
          type: 'alert'
        });
      } else {
        // ── SINGLE warehouse save (editing or no per-warehouse stocks) ──
        const almacen = (newInvItemForm.almacen || 'ALMACEN ZI').trim();
        const docId = editingInvId && (inventory||[]).find(i => i.id === editingInvId)
          ? editingInvId
          : itemId + '___' + almacen.replace(/\s+/g, '-');
        // REGLA SIMPLE: el costo ingresado = el costo guardado. Sin promedios.
        const existingItem = (inventory||[]).find(i => i.id === docId);
        const newStock = parseNum(newInvItemForm.stock);
        const prevStock = existingItem?.stock || 0;
        // Cost = EXACTLY what user typed. No calculation, no averaging.
        const costToSave = newCost > 0 ? newCost : parseNum(existingItem?.cost || 0);
        const itemData = {
          id: docId, displayId: itemId, almacen,
          desc: newInvItemForm.desc.toUpperCase(),
          category: newInvItemForm.category || 'Materia Prima',
          subcategory: newInvItemForm.subcategory || '',
          unit: newInvItemForm.unit || 'kg',
          cost: costToSave, stock: newStock,
          activo: true, minStock: parseNum(newInvItemForm.minStock||0),
          timestamp: Date.now()
        };
        await setDoc(getDocRef('inventory', docId), itemData, { merge: true });
        // Kardex only for stock changes
        const diff = newStock - prevStock;
        if (existingItem && Math.abs(diff) > 0.001) {
          await addDoc(getColRef('inventoryMovements'), {
            itemId: docId, itemDesc: itemData.desc, almacen,
            type: diff > 0 ? 'ENTRADA' : 'SALIDA',
            qty: Math.abs(diff), unitCost: costToSave,
            totalValue: Math.abs(diff) * costToSave,
            previousStock: prevStock, newStock,
            docRef: 'AJUSTE MANUAL', notes: 'Edición Inventario General',
            date: getTodayDate(), user: appUser?.name || 'Admin', timestamp: Date.now()
          });
        }
        setNewInvItemForm(initialInvItemForm); setEditingInvId(null);
        setDialog({ title: '✅ Guardado', text: `${itemId} guardado con costo $${formatNum(costToSave)}.`, type: 'alert' });
      }
    } catch(err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };
  const startEditInvItem = (mergedItem) => {
    const cleanId = mergedItem.displayId || mergedItem.id.split('___')[0] || mergedItem.id;
    // Find ALL warehouse docs for this product
    const warehouseItems = (inventory || []).filter(i => {
      const cid = i.displayId || (i.id||'').split('___')[0];
      return cid === cleanId;
    });
    const actualItem = warehouseItems.length > 0 ? warehouseItems[0] : mergedItem;
    // Pre-fill stockPerAlmacen with current stocks from each warehouse
    const stockPerAlmacen = {};
    warehouseItems.forEach(i => {
      const alm = i.almacen || 'ALMACEN ZI';
      if (stockPerAlmacen[alm] !== undefined) {
        stockPerAlmacen[alm] = String(parseNum(stockPerAlmacen[alm]) + parseNum(i.stock||0));
      } else {
        stockPerAlmacen[alm] = String(i.stock || '');
      }
    });
    // Use MULTI_EDIT flag — no single editingInvId, each warehouse is saved individually
    // Show the actual cost from the first warehouse doc (NOT a computed average)
    // The user sees the real stored cost and can update it — that cost saves to ALL warehouses
    const totalWaStk = warehouseItems.reduce((s,i) => s + parseNum(i.stock||0), 0);
    const actualCost = parseNum(actualItem.cost || 0); // Real cost from Firebase
    setEditingInvId(warehouseItems.length > 1 ? 'MULTI_EDIT' : (actualItem.id || cleanId));
    setNewInvItemForm({
      id: cleanId,
      desc: actualItem.desc,
      category: actualItem.category || 'Materia Prima',
      cost: String(actualCost || ''),  // REAL cost, not an average
      stock: String(totalWaStk || actualItem.stock || ''),
      unit: actualItem.unit || 'kg',
      almacen: actualItem.almacen || 'ALMACEN ZI',
      stockPerAlmacen,
    });
    setShowInvItemForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveMovement = async (e) => {
    if (e && e.preventDefault) e.preventDefault(); 
    const item = (inventory || []).find(i => i?.id === newMovementForm.itemId); if (!item) return;
    const qty = parseNum(newMovementForm.qty); const isAddition = newMovementForm.type === 'ENTRADA' || newMovementForm.type === 'AJUSTE (POSITIVO)';
    // Stock puede quedar negativo — se permite despacho
    let updatedCost = item?.cost || 0;
    const movCost = newMovementForm.cost ? parseNum(newMovementForm.cost) : updatedCost; 
    
    if (newMovementForm.type === 'ENTRADA') {
        const oldStock = item?.stock || 0;
        const oldCost = item?.cost || 0;
        if (oldStock + qty > 0) {
            updatedCost = ((oldStock * oldCost) + (qty * movCost)) / (oldStock + qty);
        }
    }

    const movId = Date.now().toString();
    try {
      const batch = writeBatch(db);
      batch.set(getDocRef('inventoryMovements', movId), { id: movId, date: newMovementForm.date, itemId: item.id, itemName: item.desc, type: newMovementForm.type, qty, cost: movCost, totalValue: qty * movCost, reference: newMovementForm.reference.toUpperCase(), opAsignada: newMovementForm.opAsignada || '', notes: newMovementForm.notes.toUpperCase(), timestamp: Date.now(), user: appUser?.name });
      batch.update(getDocRef('inventory', item.id), { stock: (item?.stock || 0) + (isAddition ? qty : -qty), cost: updatedCost });
      await batch.commit();

      // ── Asiento contable automático ──
      const ctaInventario = getCtaInventario(item.category);
      if (newMovementForm.type === 'ENTRADA') {
        // Débito inventario / Crédito proveedor (se deja en blanco la contraparte externa)
        await registrarAsientoContable(null, {
          debito: ctaInventario,
          credito: 'PROVEEDOR/EXTERNO',
          monto: qty * movCost,
          descripcion: `ENTRADA INVENTARIO — ${item.desc}`,
          referencia: newMovementForm.reference || 'ENT',
          fecha: newMovementForm.date,
        });
      } else if (newMovementForm.type === 'SALIDA' || newMovementForm.type === 'AUTOCONSUMO') {
        // Crédito inventario / Débito gasto
        await registrarAsientoContable(null, {
          debito: 'GASTO/EXTERNO',
          credito: ctaInventario,
          monto: qty * movCost,
          descripcion: `SALIDA INVENTARIO — ${item.desc}`,
          referencia: newMovementForm.reference || 'SAL',
          fecha: newMovementForm.date,
        });
      }

      setNewMovementForm(initialMovementForm); setDialog({title: 'Éxito', text: `Movimiento registrado. ${newMovementForm.type === 'ENTRADA' ? 'Costo promedio actualizado.' : ''}`, type: 'alert'});
    } catch (err) { setDialog({title: 'Error', text: err.message, type: 'alert'}); }
  };

  const handleSaveMov = async () => {
    if(!movForm.itemId || !parseNum(movForm.qty)) return setDialog({title:'Aviso',text:'Complete artículo y cantidad.',type:'alert'});
    // Determinar si es entrada o salida desde el tipo del formulario
    const isEntradas = movForm.type==='ENTRADA'||movForm.type==='ENTRADA_DEVOLUCION'||movForm.type==='ENTRADA_INICIAL';
    const almacenSeleccionado = movForm.almacenMov || 'ALMACEN ZI';
    const isFGGrp = movForm.itemId.startsWith('FGG::');
    const isFGItem = movForm.itemId.startsWith('FG::');
    const qty = parseNum(movForm.qty);
    const unitCostInput = parseNum(movForm.unitCost) || 0;

    if(isFGGrp || isFGItem) {
      // Find ALL FG items in the group
      const grpKey = isFGGrp ? movForm.itemId.replace('FGG::','') : movForm.itemId.replace('FG::','');
      
      // Find all matching FG items (by grpKey normalization)
      const matchingFGs = (finishedGoodsInventory||[]).filter(fg => {
        if(isFGItem && fg.id === grpKey) return true; // direct id match
        const esTermo=fg.tipoProducto==='TERMOENCOGIBLE';
        const prodNorm=(fg.producto||'').toUpperCase().replace(/\s+/g,'').replace(/[^\w]/g,'');
        const cliNorm=(fg.cliente||'').toUpperCase().replace(/\s+/g,'').replace(/[^\w]/g,'');
        const fgGrpKey=`${prodNorm}__${cliNorm}__${fg.tipoProducto||'BOLSAS'}`;
        return fgGrpKey === grpKey;
      });
      
      if(matchingFGs.length === 0) return setDialog({title:'Error',text:'Producto no encontrado.',type:'alert'});
      const esTermo = matchingFGs[0].tipoProducto==='TERMOENCOGIBLE';
      const totalStock = matchingFGs.reduce((s,fg)=>s+(esTermo?parseNum(fg.kgProducidos):parseNum(fg.millares)),0);
      const cost = unitCostInput || (esTermo ? parseNum(matchingFGs[0].costoUnitario||0) : parseNum(matchingFGs[0].costoUnitarioMillar||0));
      const isInMov = movForm.type==='ENTRADA'||movForm.type==='ENTRADA_DEVOLUCION'||movForm.type==='ENTRADA_INICIAL';
      
      if(!isInMov && qty > totalStock + 0.001) return setDialog({title:'Aviso',text:`Stock insuficiente. Disponible: ${formatNum(totalStock)} ${esTermo?'KG':'Millares'}`,type:'alert'});
      
      // Deduct/add from FG items proportionally  
      let remaining = qty;
      for(const fg of matchingFGs) {
        if(remaining <= 0.001) break;
        const fgStock = esTermo ? parseNum(fg.kgProducidos) : parseNum(fg.millares);
        if(!isInMov && fgStock <= 0) continue;
        const cantDeEste = isInMov ? qty : Math.min(remaining, fgStock);
        remaining -= cantDeEste;
        const newStk = isInMov ? fgStock + cantDeEste : Math.max(0, fgStock - cantDeEste);
        const updateFG = esTermo ? {kgProducidos: newStk} : {millares: newStk};
        await updateDoc(getDocRef('finishedGoodsInventory', fg.id), updateFG);
        await addDoc(getColRef('inventoryMovements'), {
          itemId:`FG::${fg.id}`, itemDesc:formatFGLabel(fg)||fg.producto||fg.id,
          type:movForm.type, qty:cantDeEste, unitCost:cost, totalValue:cantDeEste*cost,
          previousStock:fgStock, newStock:newStk, docRef:movForm.docRef,
          notes:movForm.notes.toUpperCase(), date:movForm.date, user:appUser?.name||'Admin',
          timestamp:Date.now(), isFG:true
        });
      }
      setMovForm({itemId:'',qty:'',unitCost:'',docRef:'',type:isEntradas?'ENTRADA':'AUTOCONSUMO',notes:'',date:getTodayDate()});
      setShowMovForm(false);
      setDialog({title:'✅ Movimiento Procesado',text:`${isInMov?'Entrada':'Salida'} registrada para ${esTermo?'KG':'Millares'}: ${formatNum(qty)}`,type:'alert'});
      return;
    }

    // MP / Consumibles — find the specific warehouse doc
    // If almacenSeleccionado is set, find that warehouse's doc specifically
    const allDocsForItem = (inventory||[]).filter(i => {
      const cid = i.displayId || (i.id||'').split('___')[0];
      return cid === movForm.itemId || i.id === movForm.itemId;
    });
    const inv = allDocsForItem.find(i => (i.almacen||'ALMACEN ZI') === almacenSeleccionado)
               || allDocsForItem[0]
               || (inventory||[]).find(i=>i.id===movForm.itemId);
    if(!inv) return setDialog({title:'Error',text:`Artículo "${movForm.itemId}" no encontrado en ${almacenSeleccionado}.`,type:'alert'});
    const docIdToUpdate = inv.id; // real Firebase doc ID
    const unitCostFinal = unitCostInput || inv.cost || 0;
    const prevStock = parseNum(inv.stock||0);
    const newStock = isEntradas ? prevStock + qty : Math.max(0, prevStock - qty);
    // Cost: WACC only on ENTRADA (incoming stock at different cost)
    const newCost = isEntradas && unitCostFinal > 0 && prevStock + qty > 0
      ? ((prevStock * parseNum(inv.cost||0)) + (qty * unitCostFinal)) / (prevStock + qty)
      : parseNum(inv.cost||0);
    const mov = {
      itemId: docIdToUpdate, itemDesc: inv.desc,
      almacen: almacenSeleccionado,
      type: movForm.type, qty, unitCost: unitCostFinal, totalValue: qty * unitCostFinal,
      previousStock: prevStock, newStock, docRef: movForm.docRef,
      notes: movForm.notes.toUpperCase(), date: movForm.date,
      user: appUser?.name||'Admin', timestamp: Date.now()
    };
    try {
      await addDoc(getColRef('inventoryMovements'), mov);
      const updateData = {stock: newStock, almacen: almacenSeleccionado};
      if(isEntradas && unitCostFinal > 0) updateData.cost = newCost;
      await setDoc(getDocRef('inventory', docIdToUpdate), updateData, {merge: true});
      setMovForm({itemId:'',qty:'',unitCost:'',docRef:'',type:isEntradas?'ENTRADA':'AUTOCONSUMO',notes:'',date:getTodayDate(),almacenMov:movForm.almacenMov});
      setShowMovForm(false);
      setDialog({title:'✅ Movimiento Procesado',text:`${isEntradas?'Entrada':'Salida'} de ${formatNum(qty)} ${inv.unit} en ${almacenSeleccionado}. Nuevo stock: ${formatNum(newStock)} ${inv.unit}`,type:'alert'});
    } catch(e){setDialog({title:'Error',text:e.message,type:'alert'});}
  };
  
  const handleDeleteInvItem = (id) => {
    setDialog({ 
      title: 'Eliminar Ítem', 
      text: `¿Eliminar ${id}?`, 
      type: 'confirm', 
      onConfirm: async () => await deleteDoc(getDocRef('inventory', id))
    });
  };

  const handleDeleteMovement = (m) => {
    requireAdminPassword(async () => {
      try {
        const batch = writeBatch(db);
        const isEntrada = /ENTRADA|POSITIVO|INICIAL/.test(String(m?.type || ''));
        const isSalida  = /SALIDA|NEGATIVO|AUTOCONSUMO|AVERIA|MUESTRA|PERDIDA/.test(String(m?.type || ''));
        const qty = parseNum(m?.qty || 0);

        if (m?.isFG) {
          // Movimiento de Producto Terminado (FG) — revertir en finishedGoodsInventory
          const fgId = String(m?.itemId || '').replace('FG::', '');
          const fgDoc = (finishedGoodsInventory || []).find(fg => fg.id === fgId);
          if (fgDoc) {
            const esTermo = fgDoc.tipoProducto === 'TERMOENCOGIBLE';
            if (isEntrada) {
              // Entrada FG → restar
              const newKg   = Math.max(0, parseNum(fgDoc.kgProducidos||0) - qty);
              const newMill = Math.max(0, parseNum(fgDoc.millares||0) - qty);
              batch.update(getDocRef('finishedGoodsInventory', fgId), esTermo ? {kgProducidos: newKg} : {millares: newMill});
            } else if (isSalida) {
              // Salida FG → sumar de vuelta
              const newKg   = parseNum(fgDoc.kgProducidos||0) + qty;
              const newMill = parseNum(fgDoc.millares||0) + qty;
              batch.update(getDocRef('finishedGoodsInventory', fgId), esTermo ? {kgProducidos: newKg} : {millares: newMill});
            }
          }
        } else {
          // Movimiento de inventario general (MP, Consumibles, Semielaborados, etc.)
          const item = (inventory || []).find(i => i?.id === m?.itemId);
          if (item) {
            // Entrada  → restar stock de vuelta
            // Salida   → sumar stock de vuelta
            // Ajuste+  → restar; Ajuste- → sumar
            const delta = isEntrada ? -qty : qty;
            const newStock = parseNum(item.stock || 0) + delta;
            batch.update(getDocRef('inventory', item.id), { stock: Math.max(0, newStock) });
          }
        }

        batch.delete(getDocRef('inventoryMovements', m.id));
        await batch.commit();
        setDialog({ title: '✅ Movimiento Anulado', text: `El stock fue revertido correctamente (${isEntrada ? '-' : '+'}${formatNum(qty)} ${m?.unit||'unid.'}).`, type: 'alert' });
      } catch(err) {
        setDialog({ title: 'Error', text: err.message, type: 'alert' });
      }
    }, 'Anular Movimiento de Kardex');
  };

  // ============================================================================
  // LOGICA COSTOS OPERATIVOS
  // ============================================================================
  const handleSaveOpCost = async (e) => {
    e.preventDefault();
    const tieneIdentificador = planDeCuentas.length > 0 ? !!newOpCostForm.cuentaContable : !!newOpCostForm.category;
    if (!tieneIdentificador || !newOpCostForm.amount) {
      return setDialog({ title: 'Aviso', text: 'Seleccione una cuenta/categoria y el monto.', type: 'alert' });
    }
    const amount = parseFloat(newOpCostForm.amount);
    if (amount <= 0) {
      return setDialog({ title: 'Aviso', text: 'El monto debe ser mayor a cero.', type: 'alert' });
    }
    try {
      const docId = `COST-${Date.now()}`;
      const month = newOpCostForm.date.substring(0, 7);
      const pdc = planDeCuentas.find(p => p.codigo === newOpCostForm.cuentaContable);
      const categoryFinal = pdc ? (pdc.nombre || pdc.subGrupo || pdc.grupo) : newOpCostForm.category;
      await setDoc(getDocRef('operatingCosts', docId), {
        ...newOpCostForm,
        category: categoryFinal,
        amount, month,
        user: appUser?.name || 'Sistema',
        timestamp: Date.now()
      });
      setNewOpCostForm(initialOpCostForm);
      setDialog({ title: 'Exito!', text: 'Costo operativo registrado correctamente.', type: 'alert' });
    } catch(err) {
      setDialog({ title: 'Error', text: err.message, type: 'alert' });
    }
  };

  const handleDeleteOpCost = (id) => {
    setDialog({
      title: 'Eliminar Costo',
      text: '¿Desea eliminar este registro de costo operativo?',
      type: 'confirm',
      onConfirm: async () => await deleteDoc(getDocRef('operatingCosts', id))
    });
  };

  const handleAddCategory = () => {
    if (!newCategoryName.trim()) return;
    if (costCategories.includes(newCategoryName.trim())) {
      setDialog({title: 'Aviso', text: 'Esta categoría ya existe.', type: 'alert'});
      return;
    }
    setCostCategories(prev => [...prev, newCategoryName.trim()]);
    setNewOpCostForm(f => ({...f, category: newCategoryName.trim()}));
    setShowNewCategoryModal(false);
    setNewCategoryName('');
    setDialog({title: 'Éxito', text: 'Categoría agregada correctamente.', type: 'alert'});
  };

  // ============================================================================
  // LOGICA VENTAS Y FACTURACIÓN
  // ============================================================================
  const handleAddClient = async (e) => {
    if (e) e.preventDefault(); if (!newClientForm.rif || !newClientForm.razonSocial) return setDialog({ title: 'Aviso', text: 'RIF y Razón Social obligatorios.', type: 'alert' });
    const rif = newClientForm.rif.toUpperCase().trim();
    const docKey = editingClientId||rif; try { await setDoc(getDocRef('clientes', docKey), { ...newClientForm, name: newClientForm.razonSocial.toUpperCase().trim(), rif, timestamp: Date.now() }, { merge: true }); setNewClientForm(initialClientForm); setEditingClientId(null); setDialog({ title: '¡Éxito!', text: 'Cliente guardado.', type: 'alert' }); } catch(err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };
